-- Luke Chapter 20
-- Theme: Authority, Accountability, and the Identity of the Son: Temple Controversies
-- 47 verses

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 20,
  'Luke 20 consists entirely of controversy dialogues in the Temple — a series of escalating confrontations between Jesus and the religious authorities (chief priests, scribes, Sadducees, and Pharisees) that constitute the public intellectual climax of his ministry before the passion. The chapter opens with the question of Jesus''s authority (vv.1-8), which he answers with a counter-question about John''s baptism that exposes the authorities'' bad faith. The Parable of the Wicked Vinedressers (vv.9-19) then reframes the entire conflict as the culmination of a long history of Israel''s rejection of God''s messengers, ending with the Son himself.',
  'The three subsequent controversies (vv.20-47) test Jesus from different ideological directions: the Herodians test him on the politically explosive question of Roman taxation (vv.20-26); the Sadducees test him with a riddle about the resurrection they do not believe in (vv.27-40); and Jesus tests the scribes with a question about Davidic sonship (vv.41-44) before issuing a public warning against the scribes'' ostentatious piety (vv.45-47). Each controversy demonstrates Jesus''s mastery: he does not merely avoid the traps but uses each encounter to advance positive theological claims about the nature of God, the resurrection, and his own identity as Lord.',
  'The question about tribute to Caesar (vv.20-26) is perhaps Jesus''s most famous political statement. The questioners have laid a dilemma: affirming taxation alienates the Jewish nationalists; denying it exposes Jesus to Roman prosecution for sedition. Jesus''s answer — "Render therefore unto Caesar the things which be Caesar''s, and unto God the things which be God''s" (v.25) — is not a political theory but an eschatological reminder: what bears Caesar''s image belongs to Caesar; what bears God''s image (the human person, Gen 1:26-27) belongs entirely to God.',
  'The Sadducees'' question about levirate marriage and resurrection (vv.27-40) receives from Jesus an answer that both refutes their materialism and makes a positive theological claim: the resurrection is not the resuscitation of earthly existence but transformation into a qualitatively new mode of being, "equal unto the angels" (isangEloi), in which marriage is irrelevant because death is irrelevant. Jesus then turns to Exodus 3:6 to demonstrate resurrection from the Torah itself — the only Scripture the Sadducees accepted as fully authoritative. His argument — "God is not a God of the dead, but of the living" — establishes that covenant relationship implies ongoing life.',
  'ἐξουσία (exousia)',
  'exousia means authority, power, the right to act — delegated or intrinsic power. It appears prominently in vv.2 and 8: "Tell us, by what authority doest thou these things? Or who is he that gave thee this authority?" (en poia exousia tauta poieis; ē tis estin ho dous soi tēn exousian tautēn). The question is the hinge of the entire chapter: if Jesus''s authority is divine (as his counter-question about John implies), then the authorities'' rejection of him is rebellion against God. If human, he is a usurper. Jesus refuses to answer directly, but the Parable of the Vinedressers (vv.9-19) and the Davidic Sonship question (vv.41-44) both answer indirectly: his authority is as the Son sent by the Father, and as the Lord whom David calls Lord.',
  '["Authority Questioned and John''s Baptism (vv.1-8)","The Parable of the Wicked Vinedressers (vv.9-19)","Tribute to Caesar: Image and Allegiance (vv.20-26)","The Sadducees and the Resurrection (vv.27-40)","David''s Son and Lord: Jesus''s Counter-Question (vv.41-44)","Warning Against the Scribes (vv.45-47)"]'
FROM books b WHERE b.name = 'Luke';

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'And it came to pass, that on one of those days, as he taught the people in the temple, and preached the gospel, the chief priests and the scribes came upon him with the elders,', 'Καὶ ἐγένετο ἐν μιᾷ τῶν ἡμερῶν ἐκείνων διδάσκοντος αὐτοῦ τὸν λαὸν ἐν τῷ ἱερῷ καὶ εὐαγγελιζομένου, ἐπέστησαν οἱ ἀρχιερεῖς καὶ οἱ γραμματεῖς σὺν τοῖς πρεσβυτέροις,', 'Kai egeneto en mia tōn hēmerōn ekeinōn didaskontos autou ton laon en tō hierō kai euangelizomenou, epestēsan hoi archiereis kai hoi grammateis sun tois presbuterois,', '"On one of those days" — the daily Temple teaching ministry established in 19:47. "Taught...and preached the gospel" (didaskontos kai euangelizomenou — teaching and evangelizing; the two activities are linked: the gospel is proclaimed through teaching) — Jesus is in the midst of active ministry when interrupted. "Came upon him" (epestēsan — stood over him, came up to him; the word suggests a sudden confrontational arrival, used of armies and officials) — the three groups together (chief priests, scribes, elders) constitute the Sanhedrin''s composition, making this an official delegation.', NULL),
  (2, 'Saying unto him, Tell us, by what authority doest thou these things? or who is he that gave thee this authority?', 'καὶ εἶπαν λέγοντες πρὸς αὐτόν, Εἰπὲ ἡμῖν ἐν ποίᾳ ἐξουσίᾳ ταῦτα ποιεῖς, ἢ τίς ἐστιν ὁ δοὺς σοί τὴν ἐξουσίαν ταύτην.', 'kai eipan legontes pros auton, Eipe hēmin en poia exousia tauta poieis, ē tis estin ho dous soi tēn exousian tautēn.', '"By what authority doest thou these things?" (en poia exousia — in what kind of authority; poia asks about the quality and source of the authority) — "these things" refers to the Temple cleansing (19:45-46) and the daily teaching. The question has a legal dimension: authorized teachers needed rabbinical ordination and appointment. Jesus has no such credentials. The question is formally respectful but designed to expose either a lack of authorization or a blasphemous claim of divine authorization.', NULL),
  (3, 'And he answered and said unto them, I will also ask you one thing; and answer me:', 'ἀποκριθεὶς δὲ εἶπεν πρὸς αὐτούς, Ἐρωτήσω ὑμᾶς κἀγὼ ἕνα λόγον, καὶ εἴπατέ μοι·', 'apokritheis de eipen pros autous, Erōtēsō humas kagō hena logon, kai eipate moi;', '"I will also ask you one thing" (Erōtēsō humas kagō hena logon — I also will ask you one word/question) — a counter-question is a recognized rabbinic method of responding to a question one judges to be in bad faith or that can best be answered by exposing the questioner''s presuppositions. Jesus is not evading but engaging at the level of the questioners'' actual motivation. "And answer me" (kai eipate moi — and tell me; the aorist imperative: give me an answer) — he expects and demands an answer, putting them in the same position they have put him.', NULL),
  (4, 'The baptism of John, was it from heaven, or of men?', 'τὸ βάπτισμα Ἰωάννου ἐξ οὐρανοῦ ἦν ἢ ἐξ ἀνθρώπων;', 'to baptisma Iōannou ex ouranou ēn ē ex anthrōpōn?', '"The baptism of John, was it from heaven, or of men?" — a brilliantly constructed dilemma. The question is not merely about John but about the source of prophetic authority. "From heaven" (ex ouranou — from heaven, the Jewish circumlocution for "from God") implies divine authorization; "of men" (ex anthrōpōn — from humans, from human decision) implies human institution. John and Jesus shared a common prophetic mission and common opposition from the same authorities; the authorities'' response to John logically implies their response to Jesus.', NULL),
  (5, 'And they reasoned with themselves, saying, If we shall say, From heaven; he will say, Why then believed ye him not?', 'οἱ δὲ συνελογίσαντο πρὸς ἑαυτοὺς λέγοντες ὅτι Ἐὰν εἴπωμεν, Ἐξ οὐρανοῦ· ἐρεῖ, Διατί οὐκ ἐπιστεύσατε αὐτῷ;', 'hoi de sunelogisanto pros heautous legontes hoti Ean eipōmen, Ex ouranou; erei, Diatī ouk episteusate autō?', '"They reasoned with themselves" (sunelogisanto pros heautous — they calculated together among themselves; the compound sunelogisanto suggests mutual deliberation, a committee decision) — they think through both horns of the dilemma before answering. "If we shall say, From heaven; he will say, Why then believed ye him not?" (Ean eipōmen...erei...Diatī ouk episteusate autō) — if John''s authority was divine, their rejection of John was rebellion against God; their authority question against Jesus falls on themselves. The conditional syllogism is airtight.', NULL),
  (6, 'But and if we say, Of men; all the people will stone us: for they be persuaded that John was a prophet.', 'ἐὰν δὲ εἴπωμεν, Ἐξ ἀνθρώπων· ὁ λαὸς ἅπας καταλιθάσει ἡμᾶς· πεπεισμένος γάρ ἐστιν Ἰωάννην προφήτην εἶναι.', 'ean de eipōmen, Ex anthrōpōn; ho laos hapas katalithasei hēmas; pepeismenos gar estin Iōannēn prophētēn einai.', '"All the people will stone us" (ho laos hapas katalithasei hēmas — all the people will stone us to death; katalithasei — a strong word, to stone thoroughly/completely; the prefix kata intensifies) — the crowd''s protection of Jesus (19:48) extends to John''s memory. Stoning was the prescribed punishment for blasphemy; denying John''s prophetic status in the presence of the people would be politically suicidal. "Persuaded that John was a prophet" (pepeismenos — perfect passive: in a state of having been persuaded, settled conviction) — the people''s conviction is firm and permanent.', NULL),
  (7, 'And they answered, that they could not tell whence it was.', 'καὶ ἀπεκρίθησαν μὴ εἰδέναι πόθεν.', 'kai apekrithēsan mē eidenai pothen.', '"They answered, that they could not tell whence it was" (apekrithēsan mē eidenai pothen — they answered that they did not know from where) — a deliberate, strategic non-answer, driven by political calculation rather than genuine uncertainty. Their refusal to answer is not intellectual humility but calculated evasion. The irony is that their non-answer reveals their true stance: they will not commit to a position they know to be morally obligatory if true. Jesus''s counter-question has exposed not their ignorance but their bad faith.', NULL),
  (8, 'And Jesus said unto them, Neither tell I you by what authority I do these things.', 'καὶ ὁ Ἰησοῦς εἶπεν αὐτοῖς, Οὐδὲ ἐγὼ λέγω ὑμῖν ἐν ποίᾳ ἐξουσίᾳ ταῦτα ποιῶ.', 'kai ho Iēsous eipen autois, Oude egō legō humin en poia exousia tauta poiō.', '"Neither tell I you by what authority I do these things" (Oude egō legō humin — nor do I tell you) — a perfectly symmetrical refusal matching theirs. This is not a mere rhetorical maneuver but a judgment: those who refuse to engage honestly with available evidence (John''s ministry) are not entitled to further revelation. The pattern recurs throughout Luke: understanding is given to those who engage honestly, withheld from those who approach for entrapment (cf. 8:10). The silence of Jesus before those who have already decided is itself a form of judgment.', NULL),
  (9, 'Then began he to speak to the people this parable; A certain man planted a vineyard, and let it forth to husbandmen, and went into a far country for a long time.', 'Ἤρξατο δὲ πρὸς τὸν λαὸν λέγειν τὴν παραβολὴν ταύτην· Ἄνθρωπός τις ἐφύτευσεν ἀμπελῶνα, καὶ ἐξέδετο αὐτὸν γεωργοῖς, καὶ ἀπεδήμησεν χρόνους ἱκανούς.', 'Ērxato de pros ton laon legein tēn parabolēn tautēn; Anthrōpos tis ephuteusen ampelōna, kai exEdeto auton geōrgois, kai apEdēmēsen chronous hikanous.', '"Began he to speak to the people" (ērxato pros ton laon — he began to the people) — the shift from the authorities (v.1-8) to the people is deliberate: the parable is public, exposing the authorities in the hearing of those they sought to maintain control over. "A certain man planted a vineyard" (Anthrōpos tis ephuteusen ampelōna) — the vineyard immediately evokes Isaiah 5:1-7, the Song of the Vineyard where the vineyard = Israel. "Went into a far country for a long time" (apEdēmēsen chronous hikanous — traveled away for considerable time) — the long absence mirrors Israel''s experience of prophetic intervals.', NULL),
  (10, 'And at the season he sent a servant to the husbandmen, that they should give him of the fruit of the vineyard: but the husbandmen beat him, and sent him away empty.', 'καὶ ἐν καιρῷ ἀπέστειλεν πρὸς τοὺς γεωργοὺς δοῦλον, ἵνα ἀπὸ τοῦ καρποῦ τοῦ ἀμπελῶνος δώσουσιν αὐτῷ· οἱ δὲ γεωργοὶ δείραντες αὐτὸν ἐξαπέστειλαν κενόν.', 'kai en kairō apesteilen pros tous geōrgous doulon, hina apo tou karpou tou ampelōnos dōsousin autō; hoi de geōrgoi deirantes auton exapesteilan kenon.', '"At the season" (en kairō — at the appointed time, the harvest time) — the owner''s request is legitimate and expected: the tenants are to render the fruit from the vineyard entrusted to them. "Beat him, and sent him away empty" (deirantes auton exapesteilan kenon — having beaten him they sent him away empty; deirō = to flay, to beat severely) — the rejection is violent and contemptuous. The servant represents the prophetic tradition: the OT prophets sent to call Israel to account for the fruit of covenant faithfulness.', NULL),
  (11, 'And again he sent another servant: and they beat him also, and entreated him shamefully, and sent him away empty.', 'καὶ προσέθετο πέμψαι ἕτερον δοῦλον· οἱ δὲ κἀκεῖνον δείραντες καὶ ἀτιμάσαντες ἐξαπέστειλαν κενόν.', 'kai prosetheto pempsai heteron doulon; hoi de kakeionon deirantes kai atimasantes exapesteilan kenon.', '"He sent another servant" (prosetheto pempsai heteron — he added/proceeded to send another; a Hebraism for continuing a repeated action) — the second sending intensifies the pattern. "Beat him also, and entreated him shamefully" (deirantes kai atimasantes — having beaten him and having dishonored him; atimazō = to treat as without honor, to insult) — the violence escalates with dishonor added to beating. The accumulating servants represent the succession of prophets rejected by Israel, a theme explicit in Luke 11:49-51 and 13:34.', NULL),
  (12, 'And again he sent a third: and they wounded him also, and cast him out.', 'καὶ προσέθετο πέμψαι τρίτον· οἱ δὲ καὶ τοῦτον τραυματίσαντες ἐξέβαλον.', 'kai prosetheto pempsai triton; hoi de kai touton traumatisantes exebalon.', '"They wounded him also, and cast him out" (traumatisantes exebalon — having wounded him they threw him out; traumatizō = to wound physically, the root of the English "trauma") — the third servant receives the most severe treatment: wounded and expelled rather than merely beaten and dismissed. The escalating series of three creates the narrative anticipation that the fourth action will either be the turn-around or the final catastrophe. In this parable, the fourth action brings the worst: the son.', NULL),
  (13, 'Then said the lord of the vineyard, What shall I do? I will send my beloved son: it may be they will reverence him when they see him.', 'εἶπεν δὲ ὁ κύριος τοῦ ἀμπελῶνος, Τί ποιήσω; πέμψω τὸν υἱόν μου τὸν ἀγαπητόν· ἴσως αὐτὸν ἰδόντες ἐντραπήσονται.', 'eipen de ho kurios tou ampelōnos, Ti poiēsō? pempsō ton huion mou ton agapēton; isōs auton idontes entrapēsontai.', '"My beloved son" (ton huion mou ton agapēton — my son, the beloved one; agapētos — the same word used at Jesus''s baptism, 3:22, and transfiguration, 9:35: "my beloved Son") — the parabolic identification of Jesus is transparent and deliberate. The audience would have recognized the allusion. "It may be they will reverence him" (isōs entrapēsontai — perhaps they will show respect; isōs = perhaps, perhaps the only time in the Gospels divine action is expressed with "perhaps") — the owner''s hope, which proves unfounded, shows the depth of his patient mercy.', NULL),
  (14, 'But when the husbandmen saw him, they reasoned among themselves, saying, This is the heir: come, let us kill him, that the inheritance may be ours.', 'ἰδόντες δὲ αὐτὸν οἱ γεωργοὶ διελογίζοντο πρὸς ἀλλήλους λέγοντες, Οὗτός ἐστιν ὁ κληρονόμος· δεῦτε ἀποκτείνωμεν αὐτόν, ἵνα ἡμῶν γένηται ἡ κληρονομία.', 'idontes de auton hoi geōrgoi dielogizonto pros allēlous legontes, Houtos estin ho klēronomos; deute apokteinōmen auton, hina hēmōn genētai hē klēronomia.', '"This is the heir: come, let us kill him, that the inheritance may be ours" (Houtos estin ho klēronomos; deute apokteinōmen auton — This one is the heir; come, let us kill him) — the tenants recognize the heir and deliberately choose murder to seize the inheritance. The logic: with the heir dead and no other successors, they can claim adverse possession of the vineyard. This reveals the nature of Israel''s rejection of Jesus: not ignorance but calculated self-interest. The chief priests and scribes listening (v.19) would have recognized themselves in the deliberating tenants.', NULL),
  (15, 'So they cast him out of the vineyard, and killed him. What therefore shall the lord of the vineyard do unto them?', 'καὶ ἐκβαλόντες αὐτὸν ἔξω τοῦ ἀμπελῶνος ἀπέκτειναν. τί οὖν ποιήσει αὐτοῖς ὁ κύριος τοῦ ἀμπελῶνος;', 'kai ekbalontes auton exō tou ampelōnos apekteinan. ti oun poiēsei autois ho kurios tou ampelōnos?', '"Cast him out of the vineyard, and killed him" (ekbalontes exō tou ampelōnos apekteinan — having cast him outside the vineyard they killed him) — "outside the vineyard" may allude to Hebrews 13:12: "Jesus...suffered without the gate." The casting out precedes the killing, perhaps reflecting crucifixion outside the city walls. "What therefore shall the lord of the vineyard do unto them?" — Jesus turns the question to the listeners, inviting them to pronounce judgment on the tenants before they realize they are pronouncing judgment on themselves.', NULL),
  (16, 'He shall come and destroy these husbandmen, and shall give the vineyard to others. And when they heard it, they said, God forbid.', 'ἐλεύσεται καὶ ἀπολέσει τοὺς γεωργοὺς τούτους, καὶ δώσει τὸν ἀμπελῶνα ἄλλοις. ἀκούσαντες δὲ εἶπαν, Μὴ γένοιτο.', 'eleusetai kai apolesei tous geōrgous toutous, kai dōsei ton ampelōna allois. akousantes de eipan, Mē genoito.', '"He shall come and destroy these husbandmen, and shall give the vineyard to others" — the verdict pronounced by the narrative itself, not by the listeners. "Shall give the vineyard to others" — the inheritance transferred: the kingdom given to a new stewardship (cf. Matt 21:43: "a nation bringing forth the fruits thereof"). "When they heard it, they said, God forbid" (Mē genoito — may it not be! let it not happen! the strongest negative expression in Greek, used by Paul in Romans for emphatic denial) — the audience recoils from the logical conclusion of their own narrative.', NULL),
  (17, 'And he beheld them, and said, What is this then that is written, The stone which the builders rejected, the same is become the head of the corner?', 'ὁ δὲ ἐμβλέψας αὐτοῖς εἶπεν, Τί οὖν ἐστιν τὸ γεγραμμένον τοῦτο, Λίθον ὃν ἀπεδοκίμασαν οἱ οἰκοδομοῦντες, οὗτος ἐγενήθη εἰς κεφαλὴν γωνίας;', 'ho de emblepsas autois eipen, Ti oun estin to gegrammenon touto, Lithon hon apedokimasan hoi oikodomountes, houtos egenēthē eis kephalēn gōnias?', '"He beheld them" (emblepsas — having looked intently at them; emblēpō = to look into, to gaze fixedly) — a penetrating look that precedes the Scriptural citation. "The stone which the builders rejected" (Lithon hon apedokimasan hoi oikodomountes) — Psalm 118:22, the same psalm cited at the Triumphal Entry (19:38). The "stone rejected by the builders" and "head of the corner" (kephalēn gōnias — cornerstone or capstone) applies to Jesus: the one declared unfit for the building by its official architects is nevertheless made its foundational stone by God.', NULL),
  (18, 'Whosoever shall fall upon that stone shall be broken; but on whomsoever it shall fall, it will grind him to powder.', 'πᾶς ὁ πεσὼν ἐπ'' ἐκεῖνον τὸν λίθον συνθλασθήσεται· ἐφ'' ὃν δ'' ἂν πέσῃ, λικμήσει αὐτόν.', 'pas ho pesōn ep'' ekeinon ton lithon sunthlasthēsetai; eph'' hon d'' an pesē, likmēsei auton.', '"Whosoever shall fall upon that stone shall be broken" (sunthlasthēsetai — will be shattered, broken to pieces; sun = together + thlaō = to crush) — stumbling over the stone results in breaking. "On whomsoever it shall fall, it will grind him to powder" (likmēsei auton — will winnow him, scatter him like chaff; likmizō = to winnow grain, to scatter like dust, then to pulverize) — the stone falls on and reduces to dust. The two directions of encounter (falling on the stone, stone falling on you) represent the two outcomes of rejection: moral collapse from stumbling, and eschatological judgment from the stone''s descent.', NULL),
  (19, 'And the chief priests and the scribes the same hour sought to lay hands on him; and they feared the people: for they perceived that he had spoken this parable against them.', 'Καὶ ἐζήτησαν οἱ γραμματεῖς καὶ οἱ ἀρχιερεῖς ἐπιβαλεῖν ἐπ'' αὐτὸν τὰς χεῖρας ἐν αὐτῇ τῇ ὥρᾳ, καὶ ἐφοβήθησαν τὸν λαόν· ἔγνωσαν γὰρ ὅτι πρὸς αὐτοὺς εἶπεν τὴν παραβολὴν ταύτην.', 'Kai ezētēsan hoi grammateis kai hoi archiereis epibalein ep'' auton tas cheiras en autē tē hōra, kai ephobēthēsan ton laon; egnōsan gar hoti pros autous eipen tēn parabolēn tautēn.', '"The same hour sought to lay hands on him" (en autē tē hōra epibalein tas cheiras — in that very hour to lay hands on him) — the parable''s transparent application to them has provoked immediate murderous impulse. "They feared the people" (ephobēthēsan ton laon — they were afraid of the people; the aorist here indicating a decisive realization of the obstacle) — the crowd''s protection is the only thing preventing immediate arrest. "They perceived that he had spoken this parable against them" (pros autous — toward/against them) — their perception is accurate; the parable was an unmistakable public indictment.', NULL),
  (20, 'And they watched him, and sent forth spies, which should feign themselves just men, that they might take hold of his words, that so they might deliver him unto the power and authority of the governor.', 'Καὶ παρατηρήσαντες ἀπέστειλαν ἐγκαθέτους ὑποκρινομένους ἑαυτοὺς δικαίους εἶναι, ἵνα ἐπιλάβωνται αὐτοῦ λόγου, ὥστε παραδοῦναι αὐτὸν τῇ ἀρχῇ καὶ τῇ ἐξουσίᾳ τοῦ ἡγεμόνος.', 'Kai paratērēsantes apesteilan enkathetous hupokrinomenous heautous dikaious einai, hina epilabōntai autou logou, hōste paradounai auton tē archē kai tē exousia tou hēgemonos.', '"Sent forth spies" (apesteilan enkathetous — dispatched plants, paid informers; enkathetos is a rare word meaning one who is set in to lay a trap, an agent provocateur) "which should feign themselves just men" (hupokrinomenous heautous dikaious einai — pretending themselves to be just/righteous; hupokrinomai = to play a role, to pretend, the root of hypocrite) — the irony is sharp: those who accuse Jesus of undermining justice send actors playing just men. "Take hold of his words" (epilabōntai autou logou — to seize hold of his word) "to deliver him unto the...governor" — the plan is to get Jesus to say something treasonous enough for Roman prosecution.', NULL),
  (21, 'And they asked him, saying, Master, we know that thou sayest and teachest rightly, neither acceptest thou the person of any, but teachest the way of God truly:', 'καὶ ἐπηρώτησαν αὐτὸν λέγοντες, Διδάσκαλε, οἴδαμεν ὅτι ὀρθῶς λέγεις καὶ διδάσκεις, καὶ οὐ λαμβάνεις πρόσωπον, ἀλλ'' ἐπ'' ἀληθείας τὴν ὁδὸν τοῦ Θεοῦ διδάσκεις·', 'kai epērōtēsan auton legontes, Didaskale, oidamen hoti orthōs legeis kai didaskeis, kai ou lambaneis prosōpon, all'' ep'' alētheias tēn hodon tou Theou didaskeis;', '"We know that thou sayest and teachest rightly" — the flattery is transparent and deliberate; the spies are establishing a premise ("you always tell the truth") before asking a question designed to make the truth dangerous. "Neither acceptest thou the person of any" (ou lambaneis prosōpon — you do not take faces, you do not show partiality; a Hebraism from the practice of favoring a person by lifting their face) — the compliment sets up the trap: if Jesus does not show partiality and always teaches truly, he cannot hedge his answer to the next question.', NULL),
  (22, 'Is it lawful for us to give tribute unto Caesar, or no?', 'Ἔξεστιν ἡμῖν Καίσαρι φόρον δοῦναι ἢ οὔ;', 'Exestin hēmin Kaisari phoron dounai ē ou?', '"Is it lawful for us to give tribute unto Caesar, or no?" (Exestin hēmin Kaisari phoron dounai ē ou — is it permitted/lawful for us to give tribute/tax to Caesar or not?) — the loaded dilemma. "Lawful" (Exestin — is it permitted, legally and morally allowable) invites a theological judgment. "Tribute to Caesar" (Kaisari phoron — the poll-tax paid to the Roman emperor, deeply resented as a symbol of subjugation; the Zealots considered it idolatrous collaboration with pagan overlords) — affirmation: loss of nationalist credibility; denial: Roman prosecution for sedition. The trap appears watertight.', NULL),
  (23, 'But he perceived their craftiness, and said unto them, Why tempt ye me?', 'κατανοήσας δὲ αὐτῶν τὴν πανουργίαν εἶπεν πρὸς αὐτούς, Τί με πειράζετε;', 'katanoēsas de autōn tēn panOurgian eipen pros autous, Ti me peirazete?', '"He perceived their craftiness" (katanoēsas autōn tēn panOurgian — having fully understood their evil cleverness; panourgia = all-working, readiness to do anything for gain, unscrupulous cunning; the same word in 2 Cor 4:2 and Eph 4:14) — Jesus sees through the flattery and the trap immediately. "Why tempt ye me?" (Ti me peirazete — why are you testing me?) — the word peirazō is used for Satan''s temptation of Jesus in 4:2; the authorities'' testing is placed in the same category as diabolical testing.', NULL),
  (24, 'Shew me a penny. Whose image and superscription hath it? They answered and said, Caesar''s.', 'Δείξατέ μοι δηνάριον· τίνος ἔχει εἰκόνα καὶ ἐπιγραφήν; ἀποκριθέντες δὲ εἶπαν, Καίσαρος.', 'Deixate moi dēnarion; tinos echei eikona kai epigraphēn? apokrithentes de eipan, Kaisaros.', '"Shew me a penny" (Deixate moi dēnarion — show me a denarius; the Roman silver coin, the standard poll-tax coin) — Jesus asks them to produce the coin, which they do, revealing they already possess it (the Zealot would have refused to carry it). "Whose image and superscription hath it?" (tinos echei eikona kai epigraphēn — whose image and inscription does it have?) — the question focuses on the coin''s identity markers. The denarius of Tiberius bore his image and the inscription "Tiberius Caesar, son of the Divine Augustus." "They answered...Caesar''s" — their own answer implicates them.', NULL),
  (25, 'And he said unto them, Render therefore unto Caesar the things which be Caesar''s, and unto God the things which be God''s.', 'ὁ δὲ εἶπεν πρὸς αὐτούς, Τοίνυν ἀπόδοτε τὰ Καίσαρος Καίσαρι καὶ τὰ τοῦ Θεοῦ τῷ Θεῷ.', 'ho de eipen pros autous, Toinun apodote ta Kaisaros Kaisari kai ta tou Theou tō Theō.', '"Render therefore unto Caesar the things which be Caesar''s" (apodote ta Kaisaros Kaisari — give back to Caesar the things of Caesar; apodidōmi = to give back, to return what is owed) — the word "give back" (not merely "give") implies the coin already belongs to Caesar by virtue of his image. "And unto God the things which be God''s" (kai ta tou Theou tō Theō) — the parallel is deliberately asymmetrical: the coin bears Caesar''s image, but humans bear God''s image (Gen 1:26-27). The comparison implies that while Caesar may claim his coinage, God claims what bears his image — the whole person.', NULL),
  (26, 'And they could not take hold of his words before the people: and they marvelled at his answer, and held their peace.', 'καὶ οὐκ ἴσχυσαν ἐπιλαβέσθαι αὐτοῦ ῥήματος ἐναντίον τοῦ λαοῦ, καὶ θαυμάσαντες ἐπὶ τῇ ἀποκρίσει αὐτοῦ ἐσίγησαν.', 'kai ouk ischusan epilabesthai autou rhēmatos enantion tou laou, kai thaumasantes epi tē apokrisei autou esigēsan.', '"Could not take hold of his words" (ouk ischusan epilabesthai autou rhēmatos — were not able to seize his word; the same verb epilambanō as in v.20) — the trap has spectacularly failed; they cannot use his answer as evidence of either sedition or collaboration. "They marvelled at his answer, and held their peace" (thaumasantes...esigēsan — having marvelled they became silent) — the wonder is not admiration but stunned defeat. The silence is the silence of those who have run out of moves in a verbal chess game.', NULL),
  (27, 'Then came to him certain of the Sadducees, which deny that there is any resurrection; and they asked him,', 'Προσελθόντες δέ τινες τῶν Σαδδουκαίων, οἱ ἀντιλέγοντες ἀνάστασιν μὴ εἶναι, ἐπηρώτησαν αὐτόν,', 'Proselthontes de tines tōn Saddoukaiōn, hoi antilegontes anastasin mē einai, epērōtēsan auton,', '"The Sadducees, which deny that there is any resurrection" (hoi antilegontes anastasin mē einai — those who contradict, saying there is no resurrection; antilegō = to speak against, to contradict) — Luke identifies the Sadducees by their distinctive theological position, which distinguished them from the Pharisees. The Sadducees accepted only the Torah (five books of Moses) as fully authoritative and found no resurrection doctrine therein. They were aristocratic and priestly, politically allied with Rome. Their question is designed to make resurrection appear absurd through a logical reductio ad absurdum.', NULL),
  (28, 'Saying, Master, Moses wrote unto us, If any man''s brother die, having a wife, and he die without children, that his brother should take his wife, and raise up seed unto his brother.', 'λέγοντες, Διδάσκαλε, Μωσῆς ἔγραψεν ἡμῖν, ἐάν τινος ἀδελφὸς ἀποθάνῃ ἔχων γυναῖκα, καὶ οὗτος ἄτεκνος ἀποθάνῃ, ἵνα λάβῃ ὁ ἀδελφὸς αὐτοῦ τὴν γυναῖκα καὶ ἐξαναστήσῃ σπέρμα τῷ ἀδελφῷ αὐτοῦ.', 'legontes, Didaskale, Mōsēs egraPSen hēmin, ean tinos adelphos apothanē echōn gunaika, kai houtos ateknos apothanē, hina labē ho adelphos autou tēn gunaika kai exanastēsē sperma tō adelphō autou.', '"Moses wrote unto us" (Mōsēs egraPSen hēmin — Moses wrote for us) — the Sadducees appeal to their only acknowledged authority: the Torah. The reference is to Levirate marriage law (Deut 25:5-10; Gen 38:8): if a married man dies childless, his brother must marry the widow to produce an heir. "Raise up seed unto his brother" (exanastēsē sperma tō adelphō — raise up offspring for his brother) — the law''s purpose was the preservation of family lineage and property within the tribe. The Sadducees will use this law to construct a reductio.', NULL),
  (29, 'There were therefore seven brethren: and the first took a wife, and died without children.', 'ἑπτὰ οὖν ἀδελφοὶ ἦσαν· καὶ ὁ πρῶτος λαβὼν γυναῖκα ἀπέθανεν ἄτεκνος·', 'hepta oun adelphoi ēsan; kai ho prōtos labōn gunaika apethanen ateknos;', '"Seven brethren" (hepta adelphoi — seven brothers) — the choice of seven is deliberate: the complete number, producing the most extreme scenario. The first brother marries and dies childless, activating the Levirate obligation for the second. The story is a legal thought-experiment designed to push the resurrection doctrine to its logical extreme. The scenario may be original to the Sadducees or drawn from a known riddle circulated in scribal debates.', NULL),
  (30, 'And the second took her to wife, and he died childless.', 'καὶ ὁ δεύτερος', 'kai ho deuteros', 'The second brother fulfills the Levirate obligation and also dies childless, triggering the same obligation for the third. The brevity of vv.30-32 in Luke''s account (compared to Mark) creates a rapid accumulation: each verse compresses the same tragic cycle — marriage, death, no children. The compression heightens the absurdity the Sadducees are building toward. Seven times the cycle repeats; seven times death wins.', NULL),
  (31, 'And the third took her; and in like manner the seven also: and they left no children, and died.', 'καὶ ὁ τρίτος ἔλαβεν αὐτήν· ὡσαύτως δὲ καὶ οἱ ἑπτά· οὐ κατέλιπον τέκνα καὶ ἀπέθανον.', 'kai ho tritos elaben autēn; hōsautōs de kai hoi hepta; ou katelipon tekna kai apethAnon.', '"In like manner the seven also...they left no children, and died" (hoi hepta; ou katelipon tekna kai apethAnon — the seven; they left no children and died) — the whole sequence is summarized in a single clause. The woman passes through seven husbands without producing a child; all seven die. The scenario is extreme to the point of dark comedy, but the Sadducees'' legal logic is internally consistent: the Levirate law creates a chain of marital obligations, and if marriage survives death (as resurrection seems to imply), the marriage chain becomes insoluble.', NULL),
  (32, 'Last of all the woman died also.', 'ὕστερον δὲ πάντων ἀπέθανεν καὶ ἡ γυνή.', 'husteron de pantōn apethanen kai hē gunē.', '"Last of all the woman died also" (husteron de pantōn apethanen kai hē gunē — last of all also the woman died) — the final death that completes the scenario. The woman, who has outlived all seven husbands, dies last. The scenario is now set: in the resurrection, she will presumably be alive simultaneously with all seven husbands. The Sadducees'' implicit conclusion: the resurrection creates an irresolvable legal and moral impossibility regarding marriage.', NULL),
  (33, 'Therefore in the resurrection whose wife of them is she? for seven had her to wife.', 'ἐν τῇ οὖν ἀναστάσει τίνος αὐτῶν γίνεται γυνή; οἱ γὰρ ἑπτὰ ἔσχον αὐτὴν γυναῖκα.', 'en tē oun anastasei tinos autōn ginetai gunē? hoi gar hepta eschon autēn gunaika.', '"Whose wife of them is she?" (tinos autōn ginetai gunē — of which of them does she become wife?) — the question assumes that resurrection life is structured by the same legal categories as earthly life. The Sadducees expect Jesus either to name one of the seven (creating injustice to the other six) or to confess the impossibility of resurrection. Their error, as Jesus will reveal, is the assumption that resurrection life = earthly life continued. They have imagined resurrection as resuscitation.', NULL),
  (34, 'And Jesus answering said unto them, The children of this world marry, and are given in marriage:', 'καὶ ἀποκριθεὶς εἶπεν αὐτοῖς ὁ Ἰησοῦς, Οἱ υἱοὶ τοῦ αἰῶνος τούτου γαμοῦσιν καὶ γαμίσκονται·', 'kai apokritheis eipen autois ho Iēsous, Hoi huioi tou aiōnos toutou gamousin kai gamiskontai;', '"The children of this world marry, and are given in marriage" (hoi huioi tou aiōnos toutou — the sons of this age; gamousin kai gamiskontai — they marry and are given in marriage; active for men, passive for women in the social context) — Jesus establishes the first term of a distinction: this age has its own structures. Marriage belongs to "this age" (tou aiōnos toutou) because it serves the purposes of this age: procreation, family continuity, property succession, social ordering. These purposes are genuinely good within this age but are not the final word.', NULL),
  (35, 'But they which shall be accounted worthy to obtain that world, and the resurrection from the dead, neither marry, nor are given in marriage:', 'οἱ δὲ καταξιωθέντες τοῦ αἰῶνος ἐκείνου τυχεῖν καὶ τῆς ἀναστάσεως τῆς ἐκ νεκρῶν οὔτε γαμοῦσιν οὔτε γαμίσκονται·', 'hoi de kataxiōthentes tou aiōnos ekeinou tuchein kai tēs anastaseōs tēs ek nekrōn oute gamousin oute gamiskontai;', '"They which shall be accounted worthy" (hoi kataxiōthentes — those having been deemed worthy, a divine passive: deemed worthy by God; the condition of entry into the age to come is God''s judgment, not human merit) "to obtain that world, and the resurrection from the dead" — the age to come is defined by resurrection life. "Neither marry, nor are given in marriage" (oute gamousin oute gamiskontai — neither do they marry nor are they given in marriage) — marriage in the resurrection age is not prohibited but unnecessary; its purposes (procreation, succession) have been transcended. The eschatological community does not need to reproduce because death has been overcome.', NULL),
  (36, 'Neither can they die any more: for they are equal unto the angels; and are the children of God, being the children of the resurrection.', 'οὐδὲ γὰρ ἀποθανεῖν ἔτι δύνανται· ἰσάγγελοι γάρ εἰσιν, καὶ υἱοί εἰσιν τοῦ Θεοῦ τῆς ἀναστάσεως υἱοὶ ὄντες.', 'oude gar apothanein eti dunantai; isangeloi gar eisin, kai huioi eisin tou Theou tēs anastaseōs huioi ontes.', '"Neither can they die any more" (oude apothanein eti dunantai — they are no longer able to die) — the inability to die is the foundational characteristic of resurrection existence. Marriage''s necessity in this age derives from human mortality (procreation replaces those who die). Remove death, remove the need for procreation; remove procreation, remove the need for marriage as this age structures it. "Equal unto the angels" (isangeloi — angel-equal; a unique word, found only here in all of Greek literature) — the comparison is specifically to angelic deathlessness, not to all angelic characteristics. "Children of God" — the resurrection brings full filial status.', NULL),
  (37, 'Now that the dead are raised, even Moses shewed at the bush, when he calleth the Lord the God of Abraham, and the God of Isaac, and the God of Jacob.', 'ὅτι δὲ ἐγείρονται οἱ νεκροί, καὶ Μωσῆς ἐμήνυσεν ἐπὶ τῆς βάτου, ὡς λέγει Κύριον τὸν Θεὸν Ἀβραὰμ καὶ Θεὸν Ἰσαὰκ καὶ Θεὸν Ἰακώβ.', 'hoti de egeirontai hoi nekroi, kai Mōsēs emēnusen epi tēs batou, hōs legei Kurion ton Theon Abraam kai Theon Isaak kai Theon Iakōb.', '"Even Moses shewed at the bush" (Mōsēs emēnusen epi tēs batou — Moses indicated at the bush) — a masterstroke of Torah argumentation aimed at Sadducees who accept only Moses. "The God of Abraham, and the God of Isaac, and the God of Jacob" (Exod 3:6) — spoken to Moses centuries after the deaths of all three patriarchs. "Shewed" (emēnusen — disclosed, revealed; the same verb used for judicial disclosure) — the burning bush passage teaches resurrection by implication. God does not say "I was the God of Abraham" (past tense) but "I am the God of Abraham" (present), implying Abraham still lives.', NULL),
  (38, 'For he is not a God of the dead, but of the living: for all live unto him.', 'Θεὸς δὲ οὐκ ἔστιν νεκρῶν ἀλλὰ ζώντων· πάντες γὰρ αὐτῷ ζῶσιν.', 'Theos de ouk estin nekrōn alla zōntōn; pantes gar autō zōsin.', '"For he is not a God of the dead, but of the living" (Theos ouk estin nekrōn alla zōntōn — God is not of the dead but of the living) — a theological axiom drawn from the argument of v.37: a covenant God who is currently "the God of Abraham" implies Abraham is currently alive with him. "For all live unto him" (pantes gar autō zōsin — for all live to/for him) — the present tense zōsin (they are living) applied to the patriarchs. Covenant relationship with God, by its nature, transcends physical death; God cannot be in covenant relationship with a non-entity.', NULL),
  (39, 'Then certain of the scribes answering said, Master, thou hast well said.', 'ἀποκριθέντες δέ τινες τῶν γραμματέων εἶπαν, Διδάσκαλε, καλῶς εἶπας.', 'apokrithentes de tines tōn grammateōn eipan, Didaskale, kalōs eipas.', '"Certain of the scribes...said, Master, thou hast well said" (Didaskale, kalōs eipas — Teacher, you have spoken well) — the scribes, who were Pharisees and therefore believed in resurrection, appreciate Jesus''s defeat of the Sadducees on their own Torah ground. The commendation is genuine, in contrast to the flattering preamble of the spies in v.21. The Pharisees and Sadducees were traditional theological opponents; the scribes here show something close to admiration for Jesus''s handling of the Sadducean trap.', NULL),
  (40, 'And after that they durst not ask him any question at all.', 'οὐκέτι γὰρ ἐτόλμων ἐπερωτᾶν αὐτὸν οὐδέν.', 'ouketi gar etolmōn eperōtan auton ouden.', '"They durst not ask him any question at all" (ouketi etolmōn eperōtan auton ouden — no longer were they daring to question him about anything) — the comprehensive defeat of all questioners: the authority question (vv.1-8), the tribute question (vv.20-26), and the resurrection question (vv.27-39) have all failed. The silence that falls across the Temple is the silence of all human opposition exhausted. Having defeated every question, Jesus now poses one of his own.', NULL),
  (41, 'And he said unto them, How say they that Christ is David''s son?', 'Εἶπεν δὲ πρὸς αὐτούς, Πῶς λέγουσιν τὸν Χριστὸν εἶναι Δαυὶδ υἱόν;', 'Eipen de pros autous, Pōs legousin ton Christon einai Dauid huion?', '"How say they that Christ is David''s son?" (Pōs legousin ton Christon einai Dauid huion — how do they say the Christ to be David''s son?) — Jesus poses a counter-question, taking the initiative after the opponents have been silenced. "They" (legousin — they say) = the scribes and popular expectation. "David''s son" is the standard messianic title, embedded in prophecy (2 Sam 7:12-16; Ps 89:3-4; Isa 11:1; Jer 23:5) and popular expectation. Jesus does not dispute the Davidic sonship but poses a problem within it.', NULL),
  (42, 'And David himself saith in the book of Psalms, The LORD said unto my Lord, Sit thou on my right hand,', 'αὐτὸς γὰρ Δαυὶδ λέγει ἐν βίβλῳ Ψαλμῶν, Εἶπεν Κύριος τῷ Κυρίῳ μου, Κάθου ἐκ δεξιῶν μου,', 'autos gar Dauid legei en biblō Psalmōn, Eipen Kurios tō Kuriō mou, Kathou ek dexiōn mou,', '"David himself saith in the book of Psalms" (autos gar Dauid legei en bibliō Psalmōn — for David himself says in the book of Psalms) — the argument appeals to David''s own testimony, creating an internal tension within the Davidic messianic tradition. Psalm 110 is the most-cited OT text in the NT, quoted more than any other. "The LORD said unto my Lord" (Eipen Kurios tō Kuriō mou — the Lord said to my Lord) — in Hebrew, YHWH said to Adonai. The Psalm identifies two Lords: YHWH (the Father) and Adonai (the one seated at the right hand).', NULL),
  (43, 'Till I make thine enemies thy footstool.', 'ἕως ἂν θῶ τοὺς ἐχθρούς σου ὑποπόδιον τῶν ποδῶν σου.', 'heōs an thō tous echthrous sou hupopodion tōn podōn sou.', '"Till I make thine enemies thy footstool" (heōs an thō tous echthrous sou hupopodion tōn podōn sou — until I place your enemies as a footstool for your feet; hupopodion — under-foot-thing, literally a footstool) — the imagery of conquered enemies as a footstool is from ancient Near Eastern royal iconography (cf. Josh 10:24 where Joshua puts his feet on the necks of defeated kings). The promised dominion is both present (seated at the right hand) and future (enemies becoming a footstool). Jesus is currently at the right hand, in the interval before all enemies are subdued.', NULL),
  (44, 'David therefore called him Lord, how is he then his son?', 'Δαυὶδ οὖν αὐτὸν Κύριον καλεῖ, καὶ πῶς αὐτοῦ υἱός ἐστιν;', 'Dauid oun auton Kurion kalei, kai pōs autou huios estin?', '"David therefore called him Lord, how is he then his son?" (Dauid auton Kurion kalei, kai pōs autou huios estin — David calls him Lord, and how is he his son?) — the logical problem: if the Messiah is David''s son (a descendant), why does David call him "Lord" (Kurios)? A son does not call his own father or ancestor "my Lord." The question forces a conclusion: the Christ is simultaneously David''s descendant (human lineage) and David''s Lord (divine identity). The paradox is resolved only by the doctrine of the Incarnation: the preexistent eternal Son became the son of David.', NULL),
  (45, 'Then in the audience of all the people he said unto his disciples,', 'Ἀκούοντος δὲ παντὸς τοῦ λαοῦ εἶπεν τοῖς μαθηταῖς αὐτοῦ,', 'Akouontos de pantos tou laou eipen tois mathētais autou,', '"In the audience of all the people" (Akouontos pantos tou laou — while all the people were hearing) — the warning against the scribes is public, given in full hearing of the crowd. The shift from addressing the authorities directly to addressing the disciples in the presence of the crowd is a pedagogical technique: teaching the disciples publicly also constitutes a warning to the scribes (who are present) and an instruction to the crowd about how to evaluate their religious leaders.', NULL),
  (46, 'Beware of the scribes, which desire to walk in long robes, and love greetings in the markets, and the highest seats in the synagogues, and the chief rooms at feasts;', 'Προσέχετε ἀπὸ τῶν γραμματέων τῶν θελόντων περιπατεῖν ἐν στολαῖς καὶ φιλούντων ἀσπασμοὺς ἐν ταῖς ἀγοραῖς καὶ πρωτοκαθεδρίας ἐν ταῖς συναγωγαῖς καὶ πρωτοκλισίας ἐν τοῖς δείπνοις,', 'Prosechete apo tōn grammateōn tōn thelontōn peripatein en stolais kai philountōn aspasmous en tais agorais kai prōtokathedrias en tais sunagōgais kai prōtoklisias en tois deipnois,', '"Beware of the scribes" (Prosechete apo tōn grammateōn — watch yourselves from the scribes; prosechō = to direct your attention toward something, to be on guard) — the warning is both negative (beware) and specific. Four marks of the corrupt religious leader: (1) "Long robes" (stolais — flowing robes that signal status); (2) "greetings in the markets" (aspasmous en tais agorais — public honorific greetings in busy places); (3) "highest seats in the synagogues" (prōtokathedrias — front-and-center seats of honor); (4) "chief rooms at feasts" (prōtoklisias — places of honor at the table). All four are about public visibility and social prestige.', NULL),
  (47, 'Which devour widows'' houses, and for a shew make long prayers: the same shall receive greater damnation.', 'οἳ κατεσθίουσιν τὰς οἰκίας τῶν χηρῶν καὶ προφάσει μακρὰ προσεύχονται· οὗτοι λήψονται περισσότερον κρίμα.', 'hoi katesthiousin tas oikias tōn chērōn kai prophasei makra proseuchontai; houtoi lēpsontai perissoteron krima.', '"Devour widows'' houses" (katesthiousin tas oikias tōn chērōn — they devour the houses of the widows; katesthiō = to eat down, to consume completely) — an accusation of financial exploitation of the most vulnerable (widows), perhaps through accepting large donations from women with limited means, or through legal manipulation of estates. The juxtaposition with "long prayers" is devastating: "for a shew make long prayers" (prophasei makra proseuchontai — for the sake of appearance they pray long prayers; prophasis = pretext, outward show) — extended public prayer conceals private predation. "Greater damnation" (perissoteron krima — more abundant judgment) — religious position amplifies responsibility and therefore judgment.', NULL)
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Luke' AND c.chapter_number = 20;
